var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"두 분 다 괜찮으신가요?","JPN":"お二人とも大丈夫でしょうか？","ENG":"You two okay back there?","TWN":"你們還好嗎？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"폭발물 전문가가 의뢰인을 폭발 위험에 노출시키다니, 부끄러워서 몸 둘 바를 모르겠군요.","JPN":"爆発物の専門家である私が依頼人を爆発の危険に晒すなんて、お恥ずかしい限りです。","ENG":"I can't believe I got my client exposed to an explosion. I feel so ashamed of myself as an explosive expert.","TWN":"真是羞愧，我身為炸彈專家，卻讓委託人落在爆炸的危險之中。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"전 괜찮아요. 구해주셔서 감사해요, 초원 씨.","JPN":"私は大丈夫です。助けていただきありがとうございます、スズキ・ナオさん。","ENG":"I'm okay. Thank you for saving us, Miss Chowon.","TWN":"我沒事，謝謝初源出手相救。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"마치 기다리고 있었던 것처럼 침식 쐐기가 차 앞을 가로막더군.","JPN":"まるで待っていたかのように侵食楔が車の行く手を阻んできた。","ENG":"They blocked off our route with a Corrupted Wedge as if they were waiting for us.","TWN":"侵食楔彷彿在等我們似地擋下我們的車。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"일반적인 움직임은 아닐세.","JPN":"普通の動きではない。","ENG":"It's not their normal behavior.","TWN":"是刻意的。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"그렇다면…… 저희를 노리기라도 한다는 건가요?","JPN":"つまり……私たちを狙っているのでしょうか？","ENG":"Then... are you saying they're after us?","TWN":"難道是……針對我們來的？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"좋지 못한 소식이군요. 현재 이 구역에서 CSE 레벨이 급속하게 상승하고 있어요.","JPN":"悪い知らせですね。現在この区域でCSEレベルが急激に上昇しています。","ENG":"Looks like we have more bad news. The CSE level of this area is rapidly increasing.","TWN":"有壞消息，現在這個區域的CSE等級急速上升中。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L15_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"3종 침식체, 신호 다수! 옵니다!","JPN":"第3種侵食体、信号多数！　来ます！","ENG":"Multiple Category 3 C.O. signals! They're coming right at us!","TWN":"有大量3類侵蝕體！來了！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이, 이젠 다 틀렸어!","JPN":"も、もうダメ！","ENG":"W-we're done for!","TWN":"我們完蛋了！"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"두 사람 다 괜찮나?","JPN":"二人とも大丈夫か？","ENG":"Are you both unharmed?","TWN":"你們二個沒事吧？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"네, 저는 괜찮습니다만…….","JPN":"はい、私は何ともありませんが……","ENG":"Yes, I think I'm good...","TWN":"是，我沒事……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L23_1","type":"dialog","speaker":"CHOWON_PERSONA_NULL_NULL","text":{"KOREA":"이상하군요. 갑자기 CSE 레벨이 정상 수치로 돌아왔습니다.","JPN":"変ですね。いきなりCSEレベルが正常な数値に戻りました。","ENG":"But that's odd. The CSE level suddenly returned to normal.","TWN":"奇怪，CSE等級突然又恢復正常了。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"방금 전까지 보이던 침식체들도…… 갑자기 모두 사라졌어요.","JPN":"先ほどまで見えていた侵食体も……いきなりすべて消えました。","ENG":"And the C.O.s we saw just a second ago... They're all gone.","TWN":"剛才那些侵蝕體……也突然都消失了。"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"침식 쐐기도 보이지 않아요. 대체 어떻게 된 거죠……?","JPN":"侵食楔も見えません。いったいどうなっているのでしょうか……？","ENG":"I can't even find the Corrupted Wedge. How's this possible...?","TWN":"侵蝕釘也沒看到了，這到底是怎麼回事……？"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DONGDAEMUN_CLOUDY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHOWON_PERSONA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……CSE레벨 안정화. 침식 경보 해제.","JPN":"……CSEレベル安定化。侵食警報解除。","ENG":"...CSE Levels stabilizing. Lifting the Corruption alert.","TWN":"……CSE等級穩定。侵蝕警報解除。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L35_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"현장의 대원들 모두 수고하셨습니다.","JPN":"現場の隊員の皆さん、お疲れさまでした。","ENG":"To all agents on the field, good work.","TWN":"現場的各位隊員，辛苦了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"후우, 끝난 건가?","JPN":"ふう、終わったのか？","ENG":"Phew. Is it over now?","TWN":"呼，結束了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"샤레이드 같은 안정화된 도시에서도 CSE 레벨이 3까지 올라가다니…….","JPN":"シャレードのように安定した都市でもCSEレベルが3まで上がるなんて……","ENG":"I can't believe the CSE Level went up to 3 in a stabilized city like Charade.","TWN":"即使在查雷德這樣穩定的城市，CSE等級也會升到3級……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"앞으로 세상이 어떻게 되려는 지 모르겠군.","JPN":"これから世界がどうなるのやら。","ENG":"What's going to happen next?","TWN":"真不知道這個世界接下來會變成什麼樣子。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐야? 기껏 서둘러서 왔더니, 시시하게 경보 해제라고?","JPN":"何？　せっかく急いで来たのに、警報解除なんてつまんないわね。","ENG":"Huh? I came here as fast as I could, but the alert's already been lifted?","TWN":"什麼啊？好不容易趕過來，結果警報已經解除了？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아, 리하르트한테 또 잔소리 듣게 생겼네.","JPN":"はあ、またリヒャルトに怒られるわ。","ENG":"*Sigh* Guess I'll get another earful from Richard again.","TWN":"唉，又要被理查嘮叨了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"고생 많으셨습니다.","JPN":"お疲れ様でした。","ENG":"Thank you for your hard work, ma'am.","TWN":"你辛苦了。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"오지만디아스님께서 손을 써주시지 않았다면, 저희만으로는 역부족이었을 겁니다.","JPN":"オジマンディアス様からのお力添えなしでは、きっと力不足でした。","ENG":"We couldn't have handled the situation without you, Miss Ozymandias.","TWN":"如果不是奧茲曼迪亞斯出手相助，光靠我們是無法應付的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"응? 뭐라고?","JPN":"え？　どういうこと？","ENG":"Huh? What?","TWN":"嗯？你說什麼？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"네? 지금 대균열 쪽에 3종 침식체를 해결하고 오신 거 아닙니까?","JPN":"えっ？　今、大亀裂のほうで第3種侵食体を処理されたのではないんですか？","ENG":"What? Didn't you just return from resolving the Category 3 from the Grand Dimension Crevice?","TWN":"啊？你不是剛剛去大峽谷那邊解決3類侵蝕體了嗎？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"으음……?","JPN":"ええっ……？","ENG":"Hmm...?","TWN":"嗯……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아하하! 그야 물론이지! 어떻게 알았대?","JPN":"あはは！　もちろんよ！　なんでわかったの？","ENG":"Ah hah hah! Of course! How did you know?","TWN":"啊哈哈！那當然了！你怎麼知道的？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L5_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"나는 이 도시에서 가장 명예로운 자라고? 그 정도 의무는 당연한 거 아니겠어?","JPN":"私はこの都市でもっとも名誉のある者よ？　このくらいの義務は当たり前じゃない。","ENG":"I'm the most honorable person in this city! It's my duty to serve!","TWN":"所以說我是這個城市裡最有榮譽感的人！那種責任不是理所當然的嗎？！"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"네, 네에……?","JPN":"は、はあ……","ENG":"H-huh...?","TWN":"啊、什麼……？"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자자~ 사소한 건 적당히 넘어가자고~","JPN":"さてさて～細かいことは置いといて～","ENG":"Now, now. Let's just skip over the trivial stuff.","TWN":"好了好了～不要糾結這麼點事了～"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"보고서에 이름 좀 부탁할게. 그게 없으면, 리하르트가 날 귀찮게 하거든.","JPN":"報告書に名前をお願いね。じゃないと、リヒャルトがうるさいのよ。","ENG":"Please put my name in the report, okay? Without it, Richard will nag me about it.","TWN":"讓我在報告上簽字吧。如果沒有名字，理查會來煩我的。"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그럼, 나는 쇼핑해야 하니까, 이만~","JPN":"じゃあ、私は買い物に行ってくるから、これで～","ENG":"Then, I gotta get back to my shopping. Bye!","TWN":"那麼，我要去逛街了，拜拜～"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER_CORRUPT2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"으으, 살려주세요…….","JPN":"うう、助けてください……","ENG":"Ngh, please, show mercy...","TWN":"嗚嗚，救命……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"적어도 이 아이만큼은 제발……!","JPN":"お願いです、せめてこの子だけは……！","ENG":"At least, spare my child, please...!","TWN":"至少饒我的孩子一命，拜託……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BABY2"},{"id":"L27_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"침식 경보가 멎었다는 급보를 받았다.","JPN":"侵食警報が止まったという急報が入った。","ENG":"We received reports that the Corruption alert had stopped.","TWN":"我收到緊急通知，說侵蝕警報已經解除了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L28_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"어떻게 된 거지, 침식체? 의도적으로 침식 현상을 조절할 수 있다고 들었는데?","JPN":"どうなっているんだ、侵食体？　意図的に侵食現象をコントロールできると聞いたが？","ENG":"What happened, C.O.? Didn't you say you could intentionally manipulate the Counterside Effect?","TWN":"侵蝕體，這是怎麼回事？你不是可以控制侵蝕現象嗎？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"뭔가가 끊었다. 연결.","JPN":"誰カニ。断チ切ラレタ。接続。","ENG":"Something cut off. The connection.","TWN":"好像斷掉，連結。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"누군가가 개입했다. 한 번 더 기회를 노려보겠다.","JPN":"誰カガ介入シタ。モウ一度チャンス、狙ウ。","ENG":"Someone. Interfering. I will try again.","TWN":"有人介入，再給一次機會。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"변명하는 것까지 인간을 똑 닮았군. 그런 건 안 배울 수 없는 건가?","JPN":"言い訳するところまで人間そっくりだな。そういったことは学ばなくてもよいのだが？","ENG":"Coming up with excuses like a human. You just had to learn that, didn't you?","TWN":"竟然還會辯解，這一點完全和人類一樣呢，好的不學，學壞的。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"할 수 없지. 다음에는 똑바로 처리하도록.","JPN":"仕方がない。次はヘマしないようにしたまえ。","ENG":"But what's done is done. Handle it better next time.","TWN":"沒辦法，下次你給我做得乾淨俐落一點。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"잠깐.","JPN":"待テ。","ENG":"Wait.","TWN":"等等。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"뭐지?","JPN":"何だ？","ENG":"What?","TWN":"做什麼？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"목격자가 있어서 죽였다. 너희 동족.","JPN":"目撃者ガイタ。殺シタ。オ前ノ同族。","ENG":"There was a witness. One of you. I killed.","TWN":"我殺掉目擊者，你的同類。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"어떻게 하지?","JPN":"ドウスル？","ENG":"What do I do?","TWN":"怎麼辦？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"어떻게 하냐고?","JPN":"どうすればいいのかって？","ENG":"What do you do?","TWN":"有什麼好怎麼辦？"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"이 도시의 지하 수로에서 마주치는 것들은 어차피 삼등 시민도 못 되는 쓰레기들이다.","JPN":"この街の地下水路で出くわすものといえば、どうせ3等市民にもなれんゴミクズどもだろう。","ENG":"Scum you find in the sewers are garbage that are not even third-grade citizens.","TWN":"會出現在下水道裡的，都是比三等市民還不如的垃圾。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"쓸데없는 소리 하지 말고 다음 연락이나 기다려.","JPN":"無駄なことを言っていないで、次の連絡を待て。","ENG":"Don't bother me with trivial matters and wait for my next call.","TWN":"廢話少說，等我下次聯絡你。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"HARVESTER_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 맡을 이번 배역은 <color=#ffd34c>은둔자</color>. 인간 사회에 잠입하는 겁니다.","JPN":"今回あなたの役は<color=#ffd34c>隠者</color>。人間社会に潜入するのです。","ENG":"The role you will be taking on is the <color=#ffd34c>hermit</color>. You will be tasked with infiltrating human society.","TWN":"你這次要扮演的角色是<color=#ffd34c>隱士</color>。潛入人類社會。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"은둔자?","JPN":"隠者？","ENG":"Hermit?","TWN":"隱士？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"유사 이래 인간은 항상 경쟁을 통해 발전해 왔습니다.","JPN":"有史以来、人間は常に競争しながら発展してきました。","ENG":"Throughout all of history, human development has been driven by competition.","TWN":"自古以來，人類總是通過競爭不斷進步。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇기에 침식체를 두려워하면서도, 한편으로는 그 힘을 손에 넣고 싶어 하죠.","JPN":"そのために侵食体を恐れながらも、その力を手に入れたがるのです。","ENG":"That's why they fear C.O.s, but also want to obtain their power.","TWN":"正因為如此，雖然害怕侵蝕體，但另一方面也渴望獲得它們的力量。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과거 리플레이서가 그랬고, 지금은 북방합의체…….","JPN":"過去ではリプレイサーが、今は北方合意体が……","ENG":"As Replacers did in the past, and now the Northern Union...","TWN":"過去是克隆集團，現在是北方和議會……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아니, 권력을 손에 쥔 자들이라면, 으레 다들 그렇게 생각하기 마련이에요.","JPN":"いや、権力を持ってる者なら誰もがそう思うでしょう。","ENG":"No, it's those in power who think this way.","TWN":"不，掌握權力的人，總是會這麼想的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 욕망을 적당히 이용하면, 나도 당신도 원하는 것을 쉽게 손에 넣을 수 있을 겁니다.","JPN":"その欲望を適度に利用すれば、私もあなたも欲しいものを簡単に手に入れられるはずですよ。","ENG":"If you use that desire appropriately, you will also easily obtain what you want.","TWN":"如果適當地利用那種欲望，我和你都能輕易得到想要的東西。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"바란다. 가능성.","JPN":"欲シイ。可能性。","ENG":"I desire. Possibilities.","TWN":"我渴望。可能性。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"내가 가지지 못한 것.","JPN":"オレニハナイモノ。","ENG":"I do not have.","TWN":"我沒能擁有的東西。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요. 그 무대는 제가 준비해드리죠.","JPN":"そうです。その舞台は私が用意しましょう。","ENG":"Yes. I'll prepare that stage for you.","TWN":"好的。那個舞台就交給我來準備吧。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 적당한 기회를 틈타서, 샤레이드 대균열 근방에 침식현상을 발생시켜 주세요.","JPN":"あなたは時機を見て、シャレード大亀裂の周辺に侵食現象を発生させてください。","ENG":"Thus, when the opportunity arises, take it and cause a Counterside Effect near Charade's Grand Dimension Crevice.","TWN":"所以請找個合適的機會，在查雷德大峽谷附近引發侵蝕現象。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 그곳에 접근할 수 있도록…….","JPN":"私がそこに接近できるように……","ENG":"So that I will be able to enter it...","TWN":"讓我能夠接近那裡……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"이해했다.","JPN":"理解シタ。","ENG":"I understand.","TWN":"……明白了。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"인간. 모두. 이익을 위해 움직인다.","JPN":"人間。皆。利益ノタメニ動ク。","ENG":"Humans. All. Act on profit.","TWN":"人類。所有人。都為了利益而行動。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"그 남자도. 그리고……. 그 여자…….","JPN":"アノ男モ。ソシテ……アノ女……","ENG":"Even that man. And... that woman...","TWN":"那個男人。還有……那個女人……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"스완. 스완 클레어도…….","JPN":"スワン。スワン・クレアモ……","ENG":"Swan. Even Swan Claire...","TWN":"史旺。史旺·克萊爾也……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"이익을 위해서라면. 죽인다. 동족조차.","JPN":"利益ノタメナラ。殺ス。同族デモ。","ENG":"For profit. Kill. Even own kind.","TWN":"為了利益。殺人。即使是同族。"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARVESTER_SWANSONG_NPC_NULL","text":{"KOREA":"큭, 큭큭큭…….","JPN":"クッ、クククッ……","ENG":"Ke, kekeke...","TWN":"咳咳，咳咳咳……"},"stage":{"bg":"UNDER","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARVESTER_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};